var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"어라, 지금 우리 둘 뿐인가?","JPN":"あれ、今俺ら二人だけか？","ENG":"Err, are we alone here?","TWN":"啊咧？現在只有我們兩個嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"지금 두목을 치면 아무도 모른다는 거네?","JPN":"今ボスを仕留めても誰にも気付かれないってこと？","ENG":"No one would know even if I jumped you right now, would they?","TWN":"那趁現在把老大幹掉也不會有人發現囉？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"하하! 농담이야. 농담.","JPN":"ハハハ！　冗談さ、冗談。","ENG":"Hah hah! Just kidding. I swear.","TWN":"哈哈哈～開玩笑的啦！呵呵～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"난 내가 좋아하는 사람은 해치지 않고 잘 따르는 편이거든.","JPN":"俺は気に入った人間に危害は加えない。むしろ従うほうだ。","ENG":"I don't hurt people I like. I even listen to them.","TWN":"我才不會對喜歡的人下手呢！我很忠心的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"뭣보다 우두머릴 친 놈이 우두머리가 되는 건 스캐빈저에서나 통하는 규칙일 뿐이고 말이야.","JPN":"ていうか、ボスの首を打ち取った者が新しいボスになるなんて、スカベンジャーでしか通じないルールだしな。","ENG":"Besides, killing the leader to take his place only works with the Scavengers.","TWN":"只是吼，在清道夫裡有個通則，就是幹掉老大的人就可以當老大。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"아, 나랑 계약하자고? 그거 좋지!","JPN":"お、俺と契約するのか？　いいぜ！","ENG":"Ah, you want to sign a contract with me. Sure!","TWN":"你要跟我簽契約喔？我當然好哇！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"우리 우정의 표시로 팔 하나 바꿔달아볼까? 마침 칼도 잘 소독해뒀다고.","JPN":"友情の証に腕を一本だけ取り替えてみるか？　ちょうど剣もしっかり消毒しておいたところだぜ。","ENG":"How'd you like to switch arms with me, as a token of our friendship? No problem cutting them off, since I've thoroughly sterilized my sword.","TWN":"慶祝我們成為朋友，不如我幫你換隻手臂當作紀念吧？正好我的刀才剛消毒過。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"……서면계약?","JPN":"……書面契約？","ENG":"... A written contract?","TWN":"……書面契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"두목! 우리가 애야?","JPN":"ボス！　俺らは子どもじゃねえんだぞ？","ENG":"Come on, Boss. We're not children anymore.","TWN":"老大！我們還是小孩子嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"펜팔을 사귀면서 놀 나이는 진작에 지났잖아?","JPN":"文通しながら遊ぶには時代も歳も違うだろ？","ENG":"We're too old to be pen pals.","TWN":"我們早就過了交筆友的年紀了吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"아픔도, 희열도 없이 사인만 교환하는 게 대체 무슨 의미가 있는데?","JPN":"痛みも喜びもなく、サインだけ交換することに一体何の意味があるんだ？","ENG":"What significance does exchanging signatures have without involving some pain... or ecstasy?","TWN":"既不難過也不開心，就只是交換簽名，這樣到底有什麼意義？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"……아, 됐어. 두목이 그렇게까지 원한다면 까짓 거 해주지 뭐.","JPN":"……まあ、いいや。ボスがそこまで望むならサインしてやる。","ENG":"... Gah, forget it. If you really want to, I'll do it.","TWN":"……算了算了，既然老大希望如此，這點小事我還做得到啦！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"그래도 마음이 바뀌면 언제든 말하라고.","JPN":"でも気が変わったらいつでも言うんだぞ。","ENG":"But if you change your mind, let me know.","TWN":"但如果你改變心意的話，隨時告訴我喔！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GLITCH_SCAVENGER_NULL_NULL","text":{"KOREA":"그때까지 이쪽 팔은 언제나 건강한 상태로 남겨둘 테니까.","JPN":"その時までこっちの腕は常に健康な状態で残しておくから。","ENG":"Until then, I'll keep this arm healthy for you.","TWN":"在那之前，我保證這隻手臂會是健全的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GLITCH_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};